class Solution {
public:
    int removeDuplicates(vector<int>& nums) {
        if (nums.empty()) return 0;
        int w = 1;
        for (int r = 1; r < (int)nums.size(); r++)
            if (nums[r] != nums[w-1]) nums[w++] = nums[r];
        return w;
    }
};

